&lt;div class=&quot;notion-cursor-default&quot;&gt;
&lt;div&gt;&amp;nbsp;&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;notion-selectable notion-sub_sub_header-block&quot; data-block-id=&quot;2ea05ea3-a2ae-808e-845a-c86986f59220&quot;&gt;
